 border-radius: 50%;
 animation: spin 1s linear infinite;
 margin-bottom: var(--now-static-space--lg, 1rem);
}

@keyframes spin {
 0% { transform: rotate(0deg); }
 100% { transform: rotate(360deg); }
}

.app__loading p {
 color: rgb(var(--now-color_text--secondary, 75,85,89));
 margin: 0;
}

